##
## Dev Environment - Input Variables
## Author: Raul Peña (rpena@shokworks.io)
##
## Purpose: Defines configurable parameters for the development environment
## These variables can be overridden via:
## - Command line: terraform apply -var="key=value"
## - .tfvars files: terraform apply -var-file="dev.tfvars"
## - Environment variables: TF_VAR_key=value
##
## Current defaults are optimized for development cost and simplicity
##

##=============================================================================
## ENVIRONMENT CONFIGURATION
##=============================================================================
## Basic environment identifiers and cloud region settings
##

variable "environment" {

  description = "Environment name (dev/staging/prod)"
  type        = string
  default     = "dev"
}

variable "azure_region" {

  description = "Azure region for deployment (e.g., eastus2, westus2, eastus22)"
  type        = string
  default     = "eastus2"
}



##=============================================================================
## ORGANIZATION IDENTIFIERS
##=============================================================================
## Used for resource naming, tagging, and resource group organization
##

variable "company_name" {

  description = "Company name (used in resource naming)"
  type        = string
  default     = "intellxxdna"
}

variable "project_name" {

  description = "Project name (used in resource naming)"
  type        = string
  default     = "lexxi"
}



##=============================================================================
## NETWORK CONFIGURATION
##=============================================================================
## Virtual Network address space
## Default: 10.0.0.0/16 provides 65,536 addresses
## Subnets defined in main.tf:
## - Database: 10.0.2.0/24 (250 usable addresses)
## - Container-Apps: 10.0.3.0/24 (250 usable addresses)
## - Legacy-Apps: 10.0.4.0/24 (250 usable addresses)
##

variable "vnet_address_space" {

  description = "VNet address space in CIDR notation"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}



##=============================================================================
## POSTGRESQL DATABASE CONFIGURATION
##=============================================================================
## PostgreSQL Flexible Server deployment settings
## Only used in dev environment for private database access
##

variable "postgres_admin_username" {

  description = "PostgreSQL administrator username (8-128 characters)"
  type        = string
  sensitive   = true
}

variable "intellxxdna_admin_username" {

  description = "Intellxxdna sername (8-128 characters)"
  type        = string
  sensitive   = true
}

variable "postgres_admin_password" {

  description = "PostgreSQL administrator password (8-128 characters, must include uppercase, lowercase, numbers, special chars)"
  type        = string
  sensitive   = true
}

variable "intellxxdna_admin_password" {

  description = "Intellxxdna username password (8-128 characters, must include uppercase, lowercase, numbers, special chars)"
  type        = string
  sensitive   = true
}



##=============================================================================
## CONTAINER APPS CONFIGURATION
##=============================================================================
## Shared Container Registry and Container Apps deployment settings
##

variable "shared_container_registry_login_server" {

  description = "Shared ACR login server (e.g., ixdnaacrshared.azurecr.io)"
  type        = string
}

variable "shared_container_registry_username" {

  description = "ACR username for pulling images"
  type        = string
  sensitive   = true
}

variable "shared_container_registry_password" {

  description = "ACR password for pulling images"
  type        = string
  sensitive   = true
}

variable "container_rd_app_image_name" {

  description = "Container App image name (e.g., rd)"
  type        = string
  default     = "rd"
}

variable "container_lexxi_app_image_name" {

  description = "Container App image name (e.g., lexxi)"
  type        = string
  default     = "lexxi"
}

variable "container_app_cpu" {

  description = "Container App CPU allocation (e.g., 1.0)"
  type        = string
  default     = "1.0"
}

variable "container_app_memory" {

  description = "Container App memory allocation (e.g., 2Gi)"
  type        = string
  default     = "2Gi"
}

variable "container_app_min_replicas" {

  description = "Minimum number of replicas"
  type        = number
  default     = 1
}

variable "container_app_max_replicas" {

  description = "Maximum number of replicas"
  type        = number
  default     = 1
}



##=============================================================================
## APPLICATION GATEWAY CONFIGURATION
##=============================================================================
## Azure Front Door Configuration
## Public-facing CDN with managed HTTPS and WAF for secure global access
##

variable "front_door_sku" {

  description = "Front Door SKU: Standard_AzureFrontDoor (~$6/month) or Premium_AzureFrontDoor (~$25/month)"
  type        = string
  default     = "Standard_AzureFrontDoor"

  validation {
    condition     = contains(["Standard_AzureFrontDoor", "Premium_AzureFrontDoor"], var.front_door_sku)
    error_message = "Front Door SKU must be Standard_AzureFrontDoor or Premium_AzureFrontDoor."
  }
}

variable "enable_front_door_waf" {

  description = "Enable Web Application Firewall on Front Door"
  type        = bool
  default     = true
}

variable "front_door_waf_mode" {

  description = "WAF mode: Detection (log threats) or Prevention (block threats)"
  type        = string
  default     = "Detection"

  validation {
    condition     = contains(["Detection", "Prevention"], var.front_door_waf_mode)
    error_message = "WAF mode must be Detection or Prevention."
  }
}



##=============================================================================
## STATIC WEB APP CONFIGURATION
##=============================================================================
## Azure Static Web App for Angular frontend deployment
## Provides GitHub Actions CI/CD integration, managed HTTPS, and global CDN
##

variable "enable_custom_domain_to_lexxi" {

  description = "Set to true only AFTER the CNAME record is created in DNS pointing to the default_host_name"
  type        = bool
  default     = false
}

variable "enable_custom_domain_to_rd" {

  description = "Set to true only AFTER the CNAME record is created in DNS pointing to the default_host_name"
  type        = bool
  default     = false
}


variable "lexxi_github_repo_url" {

  description = "GitHub repository URL (supports GitHub Enterprise URLs)"
  type        = string

  validation {
    condition     = can(regex("^https://.*\\.com/.*", var.lexxi_github_repo_url))
    error_message = "GitHub repository URL must be a valid HTTPS URL."
  }
}

variable "rd_github_repo_url" {

  description = "GitHub repository URL (supports GitHub Enterprise URLs)"
  type        = string

  validation {
    condition     = can(regex("^https://.*\\.com/.*", var.rd_github_repo_url))
    error_message = "GitHub repository URL must be a valid HTTPS URL."
  }
}

variable "github_token" {

  description = "GitHub Personal Access Token (PAT) for authentication"
  type        = string
  sensitive   = true

  validation {
    condition     = length(var.github_token) > 0
    error_message = "GitHub token cannot be empty."
  }
}

variable "lexxi_github_branch" {

  description = "GitHub branch to deploy from"
  type        = string
  default     = "develop"
}

variable "rd_github_branch" {

  description = "GitHub branch to deploy from"
  type        = string
  default     = "develop"
}

variable "swa_app_location" {

  description = "Location of the app code relative to repository root"
  type        = string
  default     = "/"
}

variable "swa_output_location" {

  description = "Build output directory (dist/ for Angular)"
  type        = string
  default     = "dist"
}

variable "swa_build_command" {

  description = "Build command to run during deployment"
  type        = string
  default     = "npm run build"
}



##=============================================================================
## KEYCLOAK CONFIGURATION
##=============================================================================
## Identity and Access Management (IAM) service configuration
## Keycloak provides OIDC/OAuth2, LDAP/AD integration, and user management
##

variable "keycloak_admin_username" {

  description = "Keycloak admin console username"
  type        = string
  default     = "admin"
  sensitive   = false
}

variable "keycloak_admin_password" {

  description = "Keycloak admin console password"
  type        = string
  sensitive   = true

  validation {
    condition     = length(var.keycloak_admin_password) >= 8
    error_message = "Keycloak admin password must be at least 8 characters long."
  }
}



##=============================================================================
## RD CONFIGURATION
##=============================================================================
## RD Container App deployment settings
##

variable "rd_swagger_username" {

  description = "RD Swagger username"
  type        = string
  sensitive   = false
}

variable "rd_swagger_pw" {

  description = "RD Swagger password"
  type        = string
  sensitive   = true
}

variable "rd_environment" {

  description = "RD environment"
  type        = string
  sensitive   = false
}

variable "rd_jwt_secret_key" {

  description = "RD JWT secret key"
  type        = string
  sensitive   = true
}

variable "rd_cors_allow_origins" {

  description = "RD CORS allow origins"
  type        = string
  sensitive   = false
}

variable "rd_access_token_expire_minutes" {

  description = "RD access token expire minutes"
  type        = string
  sensitive   = false
}

variable "rd_sentry_dsn" {

  description = "RD sentry DSN"
  type        = string
  sensitive   = false
}



##=============================================================================
## LEXXI CONFIGURATION
##=============================================================================
## Lexxi Container App deployment settings
##
variable "lexxi_openai_token" {

  description = "Lexxi OpenAI token"
  type        = string
  sensitive   = true
}

variable "lexxi_cors_allow_origins" {

  description = "Lexxi CORS allow origins"
  type        = string
  sensitive   = false
}

variable "lexxi_sentry_dsn" {

  description = "Lexxi sentry DSN"
  type        = string
  sensitive   = false
}

##
## Dev Environment - Outputs
## Author: Raul Peña (rpena@shokworks.io)
##
## Purpose: Exports key infrastructure values for reference and consumption
## These outputs can be used by:
## - Other Terraform configurations (via data sources)
## - CI/CD pipelines and automation
## - Manual reference and documentation
## - Integration with other systems
##
## Output Categories:
## - Networking: VNet ID, resource group
## - Storage: Storage account, Key Vault, Log Analytics
## - Container Registry: Shared registry reference
##
##

##=============================================================================
## RESOURCE GROUP OUTPUTS
##=============================================================================

output "resource_group_name" {

  value       = module.networking.resource_group_name
  description = "Name of the resource group"
}



##=============================================================================
## NETWORKING OUTPUTS
##=============================================================================

output "vnet_id" {
  value       = module.networking.vnet_id
  description = "Virtual Network ID"
}



##=============================================================================
## STORAGE OUTPUTS
##=============================================================================

output "storage_account_name" {

  value       = module.storage.storage_account_name
  description = "Storage Account name"
}

output "key_vault_uri" {

  value       = module.storage.key_vault_uri
  description = "Key Vault URI"
}

output "log_analytics_workspace_id" {

  value       = module.storage.log_analytics_workspace_id
  description = "Log Analytics Workspace ID"
}



##=============================================================================
## REDIS CACHE OUTPUTS (DISABLED)
##=============================================================================
## Azure Cache for Redis connection information

# output "redis_hostname" {
#   value       = module.redis.redis_hostname
#   description = "Redis cache hostname (FQDN)"
# }

# output "redis_port" {
#   value       = module.redis.redis_port
#   description = "Redis cache port (6379 for non-SSL, 6380 for SSL)"
# }

# output "redis_ssl_port" {
#   value       = module.redis.redis_ssl_port
#   description = "Redis cache SSL port"
# }

# output "redis_primary_connection_string" {
#   value       = module.redis.redis_primary_connection_string
#   description = "Primary connection string for Redis (stored in Key Vault)"
#   sensitive   = true
# }



##=============================================================================
## POSTGRESQL DATABASE OUTPUTS
##=============================================================================
## Database connection and access information for PostgreSQL Flexible Server
##=============================================================================

output "postgres_fqdn" {

  value       = azurerm_postgresql_flexible_server.postgres.fqdn
  description = "PostgreSQL Flexible Server FQDN (fully qualified domain name)"
  sensitive   = false
}

output "postgres_server_name" {

  value       = azurerm_postgresql_flexible_server.postgres.name
  description = "PostgreSQL server name"
}

output "postgres_database_name" {

  value       = azurerm_postgresql_flexible_server_database.app_database.name
  description = "Default PostgreSQL database name"
}

output "postgres_admin_username" {

  value       = var.postgres_admin_username
  description = "PostgreSQL administrator username"
  sensitive   = true
}

output "postgres_connection_string" {

  value       = "postgresql://${var.postgres_admin_username}@${azurerm_postgresql_flexible_server.postgres.fqdn}/${azurerm_postgresql_flexible_server_database.app_database.name}"
  description = "PostgreSQL connection string (password not included - provide separately)"
  sensitive   = true
}

output "postgres_connection_details" {

  value = {
    host     = azurerm_postgresql_flexible_server.postgres.fqdn
    port     = 5432
    database = azurerm_postgresql_flexible_server_database.app_database.name
    username = var.postgres_admin_username
    subnet   = "10.0.2.0/24 (database subnet)"
    access_from = [
      "10.0.3.0/24 (container-apps subnet)",
      "10.0.4.0/24 (legacy-apps subnet)"
    ]
  }
  description = "PostgreSQL Flexible Server connection details and access information"
  sensitive   = true
}



##=============================================================================
## CONTAINER APPS OUTPUTS
##=============================================================================

output "container_app_environment_id" {

  value       = azurerm_container_app_environment.env.id
  description = "Container Apps Environment resource ID"
}

output "container_lexxi_app_name" {

  value       = azurerm_container_app.lexxi.name
  description = "Container App name (lexxi)"
}

output "container_lexxi_app_fqdn" {

  value       = azurerm_container_app.lexxi.latest_revision_fqdn
  description = "Container App fully qualified domain name"
}

output "container_lexxi_app_url" {

  value       = "https://${azurerm_container_app.lexxi.latest_revision_fqdn}"
  description = "Container App URL"
}

output "container_app_configuration" {

  value = {
    name         = azurerm_container_app.lexxi.name
    environment  = azurerm_container_app_environment.env.name
    image        = "${var.shared_container_registry_login_server}/${var.container_lexxi_app_image_name}:latest"
    cpu          = var.container_app_cpu
    memory       = var.container_app_memory
    min_replicas = var.container_app_min_replicas
    max_replicas = var.container_app_max_replicas
    subnet       = "10.0.3.0/24 (container-apps subnet)"
    db_host      = "PostgreSQL disabled for cost optimization - re-enable when needed"
    db_name      = "intellxxdna_dev (when PostgreSQL re-enabled)"
    acr_server   = var.shared_container_registry_login_server
  }
  description = "Container App configuration details"
  sensitive   = false
}



##=============================================================================
## AZURE FRONT DOOR OUTPUTS
##=============================================================================
## Public access information for the Azure Front Door

output "front_door_endpoint_fqdn" {
  value       = module.front_door.endpoint_fqdn
  description = "Azure Front Door endpoint FQDN (*.azurefd.net)"
}

output "front_door_https_url" {
  value       = module.front_door.endpoint_url_https
  description = "HTTPS URL for accessing the service via Front Door"
}

output "front_door_http_url" {
  value       = module.front_door.endpoint_url_http
  description = "HTTP URL (automatically redirects to HTTPS)"
}

output "front_door_id" {
  value       = module.front_door.front_door_id
  description = "Azure Front Door profile ID"
}

output "front_door_name" {
  value       = module.front_door.front_door_name
  description = "Azure Front Door profile name"
}

output "front_door_waf_status" {
  value = {
    enabled = var.enable_front_door_waf
    mode    = var.enable_front_door_waf ? var.front_door_waf_mode : "Disabled"
  }
  description = "WAF configuration status"
}

output "front_door_configuration" {
  value       = module.front_door.front_door_configuration
  description = "Front Door configuration summary"
}

output "front_door_access_instructions" {
  value       = module.front_door.access_instructions
  description = "Instructions for accessing the Azure Front Door"
}



##=============================================================================
## STATIC WEB APP OUTPUTS (Lexxi )
##=============================================================================
## Angular frontend deployment information and access URLs

output "lexxi_static_web_app_id" {
  value       = module.static_web_app_lexxi.static_web_app_id
  description = "Lexxi Static Web App resource ID"
}

output "lexxi_static_web_app_name" {
  value       = module.static_web_app_lexxi.static_web_app_name
  description = "Lexxi Static Web App resource name"
}

output "lexxi_static_web_app_default_host_name" {
  value       = module.static_web_app_lexxi.default_host_name
  description = "Default hostname for Static Web App (*.azurestaticapps.net)"
}

output "lexxi_static_web_app_url" {
  value       = module.static_web_app_lexxi.frontend_url
  description = "Public HTTPS URL for accessing the Angular frontend"
}

output "lexxi_static_web_app_deployment_token" {
  value       = module.static_web_app_lexxi.deployment_token
  description = "Deployment token for GitHub Actions (add to repository secrets as LEXXI_AZURE_STATIC_WEB_APPS_API_TOKEN)"
  sensitive   = true
}

output "lexxi_static_web_app_configuration" {
  value       = module.static_web_app_lexxi.configuration_summary
  description = "Static Web App configuration details"
  sensitive   = false
}

output "lexxi_static_web_app_github_setup" {
  value       = module.static_web_app_lexxi.github_actions_instructions
  description = "GitHub Actions setup instructions for Static Web App deployment"
}



##=============================================================================
## STATIC WEB APP OUTPUTS - RD
##=============================================================================
## Angular frontend deployment information and access URLs for RD

output "rd_static_web_app_id" {
  value       = module.static_web_app_rd.static_web_app_id
  description = "Static Web App resource ID for RD"
}

output "rd_static_web_app_name" {
  value       = module.static_web_app_rd.static_web_app_name
  description = "Static Web App resource name for RD"
}

output "rd_static_web_app_default_host_name" {
  value       = module.static_web_app_rd.default_host_name
  description = "Default hostname for RD Static Web App (*.azurestaticapps.net)"
}

output "rd_static_web_app_url" {
  value       = module.static_web_app_rd.frontend_url
  description = "Public HTTPS URL for accessing the RD Angular frontend"
}

output "rd_static_web_app_deployment_token" {
  value       = module.static_web_app_rd.deployment_token
  description = "Deployment token for GitHub Actions for RD (add to repository secrets as AZURE_STATIC_WEB_APPS_API_TOKEN)"
  sensitive   = true
}

output "rd_static_web_app_configuration" {
  value       = module.static_web_app_rd.configuration_summary
  description = "Static Web App configuration details for RD"
  sensitive   = false
}

output "rd_static_web_app_github_setup" {
  value       = module.static_web_app_rd.github_actions_instructions
  description = "GitHub Actions setup instructions for RD Static Web App deployment"
}



##=============================================================================
## KEYCLOAK IAM OUTPUTS
##=============================================================================
## Identity and Access Management service information
## Keycloak provides OIDC/OAuth2, LDAP/AD integration, and user management

output "keycloak_container_app_name" {
  value       = azurerm_container_app.keycloak.name
  description = "Keycloak Container App name"
}

output "keycloak_container_app_fqdn" {
  value       = azurerm_container_app.keycloak.latest_revision_fqdn
  description = "Keycloak Container App fully qualified domain name"
}

output "keycloak_container_app_url" {
  value       = "https://${azurerm_container_app.keycloak.latest_revision_fqdn}"
  description = "Direct HTTPS URL to Keycloak Container App"
}

output "keycloak_admin_username" {
  value       = var.keycloak_admin_username
  description = "Keycloak admin console username"
  sensitive   = false
}

output "keycloak_admin_password" {
  value       = var.keycloak_admin_password
  description = "Keycloak admin password (required for Terraform keycloak provider)"
  sensitive   = true
}

output "keycloak_provider_url" {
  value       = "https://${azurerm_container_app.keycloak.latest_revision_fqdn}/auth"
  description = "Keycloak base URL (required for Terraform keycloak provider)"
  sensitive   = false
}

output "keycloak_database_name" {
  value       = azurerm_postgresql_flexible_server_database.keycloak_database.name
  description = "Dedicated PostgreSQL database for Keycloak"
  sensitive   = false
}

output "keycloak_database_connection" {
  value = {
    host     = azurerm_postgresql_flexible_server.postgres.fqdn
    port     = 5432
    database = azurerm_postgresql_flexible_server_database.keycloak_database.name
    username = var.postgres_admin_username
    driver   = "PostgreSQL JDBC Driver"
    jdbc_url = "jdbc:postgresql://${azurerm_postgresql_flexible_server.postgres.fqdn}/${azurerm_postgresql_flexible_server_database.keycloak_database.name}"
  }
  description = "Keycloak database connection information"
  sensitive   = true
}

output "keycloak_configuration" {
  value = {
    container_app_name    = azurerm_container_app.keycloak.name
    image                 = "keycloak/keycloak:latest"
    cpu                   = 1.0
    memory                = "2Gi"
    min_replicas          = 1
    max_replicas          = 2
    database_isolation    = "Separate 'keycloak' database for data isolation"
    admin_console_enabled = true
    auth_protocols        = ["OIDC", "OAuth2", "SAML2"]
    identity_providers    = ["LDAP/Active Directory", "Keycloak Realms"]
  }
  description = "Keycloak configuration summary"
  sensitive   = false
}

output "keycloak_access_instructions" {
  value = {
    direct_access    = "https://${azurerm_container_app.keycloak.latest_revision_fqdn}/auth/admin/"
    admin_username   = var.keycloak_admin_username
    admin_password   = "Stored in tfstate file (sensitive)"
    front_door_route = "https://${module.front_door.endpoint_fqdn}/auth/admin/"
    database         = azurerm_postgresql_flexible_server_database.keycloak_database.name
    next_steps = [
      "1. Access Keycloak Admin Console via Front Door",
      "2. Configure LDAP/Active Directory integration",
      "3. Create realms for different applications",
      "4. Configure OAuth2/OIDC clients",
      "5. Monitor deployments via GitHub Actions"
    ]
  }
  description = "Instructions for accessing and configuring Keycloak"
  sensitive   = false
}

output "keycloak_front_door_url" {
  value       = "https://${module.front_door.endpoint_fqdn}/auth/"
  description = "Keycloak admin console URL via Azure Front Door"
}

output "keycloak_front_door_admin_url" {
  value       = "https://${module.front_door.endpoint_fqdn}/auth/admin/"
  description = "Keycloak admin console URL via Azure Front Door (admin interface)"
}

##
## Storage Module - Outputs
## Author: Raul Peña (rpena@shokworks.io)
##
## Purpose: Exports storage infrastructure identifiers and endpoints
## These outputs enable other modules to access and reference storage resources
##

##=============================================================================
## STORAGE ACCOUNT OUTPUTS
##=============================================================================
## Primary storage resource identifiers and endpoints

output "storage_account_id" {
  value       = azurerm_storage_account.sa.id
  description = "ID of the storage account"
}

output "storage_account_name" {
  value       = azurerm_storage_account.sa.name
  description = "Name of the storage account"
}

output "storage_account_primary_blob_endpoint" {
  value       = azurerm_storage_account.sa.primary_blob_endpoint
  description = "Primary blob endpoint"
}

output "storage_container_backup_id" {
  value       = azurerm_storage_container.backup.id
  description = "ID of the backup storage container"
}

output "storage_container_logs_id" {
  value       = azurerm_storage_container.logs.id
  description = "ID of the logs storage container"
}

##=============================================================================
## KEY VAULT OUTPUTS
##=============================================================================
## Key Vault resource identifiers for secret management

output "key_vault_id" {
  value       = azurerm_key_vault.kv.id
  description = "ID of the Key Vault"
}

output "key_vault_uri" {
  value       = azurerm_key_vault.kv.vault_uri
  description = "URI of the Key Vault"
}

##=============================================================================
## LOG ANALYTICS OUTPUTS
##=============================================================================
## Log Analytics workspace for centralized monitoring and logging

output "log_analytics_workspace_id" {
  value       = azurerm_log_analytics_workspace.law.id
  description = "ID of the Log Analytics Workspace"
}

output "log_analytics_workspace_key" {
  value       = azurerm_log_analytics_workspace.law.primary_shared_key
  sensitive   = true
  description = "Primary shared key for Log Analytics Workspace"
}

