  description = "Keycloak admin console URL via Azure Front Door"
}

output "keycloak_front_door_admin_url" {
  value       = "https://${module.front_door.endpoint_fqdn}/auth/admin/"
  description = "Keycloak admin console URL via Azure Front Door (admin interface)"
}

