##=============================================================================
## Lexxi Container App deployment settings
##
variable "lexxi_openai_token" {

  description = "Lexxi OpenAI token"
  type        = string
  sensitive   = true
}

variable "lexxi_cors_allow_origins" {

  description = "Lexxi CORS allow origins"
  type        = string
  sensitive   = false
}

variable "lexxi_sentry_dsn" {

  description = "Lexxi sentry DSN"
