# Admin credentials written to config file at startup from Key Vault env vars
command = [
  "/bin/sh", "-c",
  "printf '[mlflow]\\ndefault_permission = NO_PERMISSIONS\\ndatabase_uri = sqlite:////tmp/auth.db\\nadmin_username = %s\\nadmin_password = %s\\n' \"$MLFLOW_ADMIN_USERNAME\" \"$MLFLOW_ADMIN_PASSWORD\" > /tmp/basic_auth.ini && MLFLOW_AUTH_CONFIG_PATH=/tmp/basic_auth.ini mlflow server --app-name basic-auth --backend-store-uri $MLFLOW_BACKEND_STORE_URI --artifacts-destination $MLFLOW_ARTIFACT_ROOT --host 0.0.0.0 --port 5000 --allowed-hosts ${local.resource_prefix}-mlflow.${azurerm_container_app_environment.env.default_domain},api-dev.ixxdna.com"
]

env {
  name  = "MLFLOW_BACKEND_STORE_URI"
  value = azurerm_key_vault_secret.mlflow_backend_store_uri.value
}

